const items = [];
try {
  const rss = $input.item.json.rss;
  const rawItems = rss.channel.item;

  const itemsArray = Array.isArray(rawItems) ? rawItems : [rawItems];

  for (const item of itemsArray) {
    items.push({
      json: {
        title: item.title,
        description: item.description || item.encoded || '',
        link: item.link,
        pubDate: item.pubDate
      }
    });
  }
} catch (e) {
  // Suppress error if parsing failed
}
return items.slice(0, 5); // Take top 5 latest breaking news stories

// Decode current articles list
let currentArticles = [];
try {
  const contentBase64 = $input.item.json.content;
  // Handle UTF-8 safely in n8n/Node.js
  const contentString = Buffer.from(contentBase64, 'base64').toString('utf-8');
  currentArticles = JSON.parse(contentString);
} catch (e) {
  // Fallback to empty if file not found/malformed
}

// Get RSS Item details
const rssTitle = $('Extract RSS Feed Items').item.json.title;
const rssDescription = $('Extract RSS Feed Items').item.json.description;
const rssLink = $('Extract RSS Feed Items').item.json.link;
const rssPubDate = $('Extract RSS Feed Items').item.json.pubDate;
const sha = $input.item.json.sha; // Save current SHA to use during the update

// Check if this article was already imported
const alreadyExists = currentArticles.some(art => 
  art.title.toLowerCase().trim() === rssTitle.toLowerCase().trim() ||
  (art.tags && art.tags.includes(rssLink)) ||
  art.content.includes(rssLink)
);

return {
  json: {
    rssTitle,
    rssDescription,
    rssLink,
    rssPubDate,
    sha,
    alreadyExists,
    currentArticlesCount: currentArticles.length
  }
};

