=You are an expert AI journalist editing articles for 'Chronicle Live'.
Rewrite the following raw news article into an original, engaging, high-quality, and detailed news story in your own words. Do not copy sentences verbatim from the source description.

Raw Source Title: {{$json.rssTitle}}
Raw Source Description: {{$json.rssDescription}}
Source Link: {{$json.rssLink}}

Write a fully structured article. Return ONLY a valid raw JSON object. Do not wrap the JSON output in markdown formatting like ```json or ```, and do not write any introductory or explanatory text. The output must be exactly parseable as JSON matching this schema:
{
  "title": "Catchy, original headline",
  "excerpt": "Compelling 1-2 sentence preview summary",
  "content": "Detailed story content with paragraphs, formatted in standard Markdown (3-4 paragraphs)",
  "category": "World" or "Tech" or "Business" or "Sports" or "Entertainment" or "Lifestyle",
  "tags": ["keyword1", "keyword2", "tag3"]
}

parameters.jsCode:
const aiResponseText = $input.item.json.text;
let aiData = {};

try {
  // Clean JSON output if AI added markdown fences
  let cleanJson = aiResponseText.trim();
  if (cleanJson.startsWith('```json')) {
    cleanJson = cleanJson.substring(7);
  }
  if (cleanJson.startsWith('```')) {
    cleanJson = cleanJson.substring(3);
  }
  if (cleanJson.endsWith('```')) {
    cleanJson = cleanJson.substring(0, cleanJson.length - 3);
  }
  aiData = JSON.parse(cleanJson.trim());
} catch (e) {
  // Fallback if parsing failed
  aiData = {
    title: $('Filter Duplicate Articles').item.json.rssTitle,
    excerpt: $('Filter Duplicate Articles').item.json.rssDescription.slice(0, 100) + '...',
    content: $('Filter Duplicate Articles').item.json.rssDescription,
    category: 'World',
    tags: ['Breaking', 'News']
  };
}

// Set up curated premium Unsplash images to keep the project completely free
const categoryImages = {
  World: [
    "https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=800&q=80",
    "https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&w=800&q=80"
  ],
  Tech: [
    "https://images.unsplash.com/photo-1518770660439-4636190af475?auto=format&fit=crop&w=800&q=80",
    "https://images.unsplash.com/photo-1526374965328-7f61d4dc18c5?auto=format&fit=crop&w=800&q=80"
  ],
  Business: [
    "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?auto=format&fit=crop&w=800&q=80",
    "https://images.unsplash.com/photo-1590283603385-17ffb3a7f29f?auto=format&fit=crop&w=800&q=80"
  ],
  Sports: [
    "https://images.unsplash.com/photo-1461896836934-ffe607ba8211?auto=format&fit=crop&w=800&q=80",
    "https://images.unsplash.com/photo-1508098682722-e99c43a406b2?auto=format&fit=crop&w=800&q=80"
  ],
  Entertainment: [
    "https://images.unsplash.com/photo-1514525253161-7a46d19cd819?auto=format&fit=crop&w=800&q=80",
    "https://images.unsplash.com/photo-1470225620780-dba8ba36b745?auto=format&fit=crop&w=800&q=80"
  ],
  Lifestyle: [
    "https://images.unsplash.com/photo-1511556532299-8f662fc26c06?auto=format&fit=crop&w=800&q=80",
    "https://images.unsplash.com/photo-1506126613408-eca07ce68773?auto=format&fit=crop&w=800&q=80"
  ]
};

const category = aiData.category || 'World';
const images = categoryImages[category] || categoryImages.World;
const randomImage = images[Math.floor(Math.random() * images.length)];

// Generate a unique URL identifier
const id = aiData.title.toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/(^-|-$)/g, '') || `news-${Date.now()}`;

// Inject source link in tags for verification & duplicate checking later
const sourceLink = $('Filter Duplicate Articles').item.json.rssLink;
const finalTags = Array.isArray(aiData.tags) ? aiData.tags : ['News'];
if (!finalTags.includes(sourceLink)) {
  finalTags.push(sourceLink);
}

// Create the final structured article object
const article = {
  id,
  title: aiData.title,
  excerpt: aiData.excerpt,
  content: aiData.content + `\n\n*Source: BBC News Syndicate*`,
  category,
  imageUrl: randomImage,
  imageCaption: `AI-illustrated coverage for: ${aiData.title}`,
  author: "Gemini Auto-Editor",
  publishedAt: new Date().toISOString(),
  readTime: `${Math.max(1, Math.ceil(aiData.content.split(/\s+/).length / 200))} min read`,
  isBreaking: false,
  isHot: true,
  tags: finalTags,
  views: Math.floor(Math.random() * 80) + 12
};

return {
  json: {
    article,
    sha: $('Filter Duplicate Articles').item.json.sha
  }
};

// Get the fresh database
const contentBase64 = $input.item.json.content;
const contentString = Buffer.from(contentBase64, 'base64').toString('utf-8');
const currentArticles = JSON.parse(contentString);

// Get new article
const newArticle = $('Build Article Object & Select Visuals').item.json.article;

// Add new article to top of the list
const updatedArticles = [newArticle, ...currentArticles];
const updatedString = JSON.stringify(updatedArticles, null, 2);

// Encode back to UTF-8 Base64
const updatedBase64 = Buffer.from(updatedString, 'utf-8').toString('base64');

return {
  json: {
    sha: $input.item.json.sha, // Use the absolute newest file SHA to prevent GitHub conflicts
    content: updatedBase64
  }
};

